UPDATE BUSINESS_CHANGE_LOG
SET APPROVAL_STATUS = #{approvalStatus},
    QUEUE_DECISION_CODE = #{queueDecisionCode}
WHERE QUEUE_ID = #{queueId}

UPDATE DEPLOYABLE_DB_PATCH_QUEUE SET APPROVAL_STATUS = #{approvalStatus}, BLOCK_REASON = #{blockReason}, APPROVED_BY = #{approvedBy}, APPROVED_AT =
CURRENT_DATETIME null , REJECTED_BY = #{rejectedBy}, REJECTED_AT =
CURRENT_DATETIME null , UPDATED_AT = CURRENT_DATETIME, UPDATED_BY = #{updatedBy} WHERE QUEUE_ID = #{queueId}

UPDATE DEPLOYABLE_DB_PATCH_QUEUE
SET APPLY_STATUS = #{applyStatus},
    BLOCK_REASON = #{blockReason},
    UPDATED_AT = CURRENT_DATETIME,
    UPDATED_BY = #{updatedBy}
WHERE QUEUE_ID = #{queueId}
